def main():
    db = SessionLocal()
    inserted = 0
    skipped = 0
    not_found = []

    for city_name, attractions in ATTRACTIONS_DATA.items():
        city = db.query(City).filter(City.name == city_name).first()
        if not city:
            not_found.append(city_name)
            continue
        for a in attractions:
            existing = db.query(Attraction).filter(
                Attraction.name == a["name"],
                Attraction.city_id == city.id
            ).first()
            if existing:
                skipped += 1
                continue
            db.add(Attraction(
                name=a["name"],
                city_id=city.id,
                category=a["category"],
                latitude=a["lat"],
                longitude=a["lon"],
            ))
            inserted += 1
    db.commit()
    print(f"Inserted: {inserted}, Skipped: {skipped}")
    if not_found:
        print(f"Cities not found in DB: {not_found}")
    db.close()

if __name__ == "__main__":
    main()